#include<bits/stdc++.h>
using namespace std;
int n,q,w[1010][1010],ul[1010][1010],ur[1010][1010],dl[1010][1010],dr[1010][1010];
int fa[1000010],ans[1000010];
char a[1010][1010];
set<int> s[1000010];
pair<int,int> p[1000010];
int dx[4]={1,0,-1,0};
int dy[4]={0,1,0,-1};
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
int id(int x,int y)
{
    return (x-1)*n+y;
}
int getx(int x)
{
    return (x-1)/n+1;
}
int gety(int x)
{
    return (x-1)%n+1;
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n*n;i++)
    {
        fa[i]=i;
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            cin>>a[i][j];
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)if(a[i][j]=='.')
        {
            ul[i][j]=min({ul[i-1][j-1],ul[i][j-1],ul[i-1][j]})+1;
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=n;j>=1;j--)if(a[i][j]=='.')
        {
            ur[i][j]=min({ur[i-1][j+1],ur[i][j+1],ur[i-1][j]})+1;
        }
    }
    for(int i=n;i>=1;i--)
    {
        for(int j=1;j<=n;j++)if(a[i][j]=='.')
        {
            dl[i][j]=min({dl[i+1][j-1],dl[i][j-1],dl[i+1][j]})+1;
        }
    }
    for(int i=n;i>=1;i--)
    {
        for(int j=n;j>=1;j--)if(a[i][j]=='.')
        {
            dr[i][j]=min({dr[i+1][j+1],dr[i][j+1],dr[i+1][j]})+1;
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            w[i][j]=min({ul[i][j],ur[i][j],dl[i][j],dr[i][j]})*2-1;
            p[id(i,j)]={w[i][j],id(i,j)};
        }
    }
    sort(p+1,p+1+n*n,greater<pair<int,int>>());
    scanf("%d",&q);
    for(int i=1;i<=q;i++)
    {
        int ax,ay,bx,by;
        scanf("%d%d%d%d",&ax,&ay,&bx,&by);
        s[id(ax,ay)].insert(i);
        s[id(bx,by)].insert(i);
    }
    for(int i=1;i<=n*n;i++)
    {
        int x=getx(p[i].second),y=gety(p[i].second);
        int f=find(p[i].second),k=p[i].first;
        if(a[x][y]=='#')
        {
            continue;
        }
        for(int j=0;j<4;j++)
        {
            int xx=x+dx[j],yy=y+dy[j];
            int tf=find(id(xx,yy));
            if(xx<1||xx>n||yy<1||yy>n||w[xx][yy]<w[x][y]||f==tf)
            {
                continue;
            }
            int fx=f,fy=tf;
            if(s[fx].size()>s[fy].size())
            {
                swap(fx,fy);
            }
            fa[fx]=f=fy;
            for(int l:s[fx])
            {
                if(s[fy].count(l))
                {
                    ans[l]=k;
                    s[fy].erase(l);
                }
                else
                {
                    s[fy].insert(l);
                }
            }
            s[fx].clear();
        }
    }
    for(int i=1;i<=q;i++)
    {
        printf("%d\n",ans[i]);
    }
    return 0;
}
